export enum UserStatus {
  Active = 'ACTIVE',
  Inactive = 'INACTIVE',
  Banned = 'BANNED'
}

export default class UserService {
  private status: any;

  constructor(rawData: any) {
    this.status = rawData.status as UserStatus;
  }

  async getUser(id: string): Promise<{ name: string; status: UserStatus }> {
    const response = await fetch(`/api/users/${id}`);
    const data = await response.json();
    if (!data) throw new Error('User not found');
    return data as { name: string; status: UserStatus };
  }

  interface Config {
    timeout: number;
    retries: number;
  }

  type ExtendedConfig = Config & { debug: boolean };

  async connectToDb(config: ExtendedConfig): Promise<void> {
    const conn = await openConnection(config);
    try {
      await conn.query('SELECT 1');
    } finally {
      await conn.close();
    }
  }
}
